@startuml
skinparam packageStyle rectangle

package "edu" {
    namespace fiuba.algoChess.interfaz.controladores {
        class AceptarNombresHandler <<C>> {
            - TFnombreJugador1 : TextField
            - TFnombreJugador2 : TextField
            - popupNombres : Popup
            + stage : Stage

            + AceptarNombresHandler()
            o handle()
        }

        class AtacarPiezaHandler <<C>> {
            ^ stage : Stage
            ^ tFX : TextField
            # stage : Stage

            + AtacarPiezaHandler()
            o handle()
        }

        class CancelarNombresHandler <<C>> {
            * popupNombres : Popup
            ~ stage : Stage

            + CancelarNombresHandler()
            o handle()
        }

        class CrearPiezaHandler <<C>> {
            ^ head : HBox
            ^ nombrePieza : String
            ^ etapaUbicar : Etapa
            ^ x : TextField
            ^ y : TextField

            + CrearPiezaHandler()
            o handle()
        }

        class CurarPiezaHandler <<C>> {
            ^ stage : Stage
            ^ iFX : TextField
            ^ tfY : TextField

            + CurarPiezaHandler()
            o handle()
        }

        class IniciarJuegoHandler <<C>> {

        }

        class JugarHandler <<C>> {
            ^ stage : Stage

            + JugarHandler()
            o handle(t)
        }

        class SalirHandler <<C>> {

            o handle()
        }

        class UbicarPiezaHandler <<C>> {
            [] head : VBox
            [ listaPieza : HashMap<String, Class> ]
            [] nombrePieza : String
            [] stagePrincipal : Stage
            [] stageUbicar : Stage
            [] tfX : TextField
            [] tfY : TextField

            + UbicarPiezaHandler()
            o alerta3seg()
            o handle()
        }
    }

    namespace javafx.event {
        abstract EventHandler <T extends Event> 
    }
}

' Relationships from handlers to views/other components
Aceptarnameshandler --> SegundaEtapa : segundaEtapa
Atacarpiezahandler --> PantallaPrincipal : pantallaPrincipal
CancelarNombreshandler --> VistaTablero : vistaTablero
Crearpiezahandler --> SegundaEtapa : segundaEtapa
Curarpiezahandler --> MapaVista : mapaView
Iniciargamehandler --> Piezaview : piezaView
Salirhandler --> Emisor : emisor
ubicarpiezahandler --> Juego : juego
ubicarpiezahandler --> BandoDeLaPieza : bandoPiezas


note right of ubicarpiezahandler::listaPieza\n[HashMap] \nStores piece types\nto be created during game setup



@enduml
